const msg = $input.first().json.message;
const text = (msg.text || '').trim();
const chatId = msg.chat.id;
const username = msg.from?.username || 'User';

let command = 'chat';
let params = '';

if (text.startsWith('/')) {
  const parts = text.split(' ');
  command = parts[0].toLowerCase().replace(/@.*/, '');
  params = parts.slice(1).join(' ');
} else {
  params = text;
}

const routeMap = {
  '/start': 'start',
  '/niche': 'set_niche',
  '/brand': 'set_brand',
  '/research': 'research',
  '/create': 'create',
  '/post': 'post',
  '/analytics': 'analytics',
  '/report': 'report',
  '/monetize': 'monetize',
  '/status': 'status',
  '/settings': 'settings',
  '/help': 'help'
};

return [{
  json: {
    route: routeMap[command] || 'chat',
    command: command,
    params: params,
    chatId: chatId,
    username: username,
    timestamp: new Date().toISOString()
  }
}];

// ============================================
// FREE AI PROVIDER ROUTER
// Tries providers in order: Groq -> Gemini -> Ollama -> HuggingFace
// ============================================

const prompt = $input.first().json.prompt || $input.first().json.params || '';
const chatId = $input.first().json.chatId;

// Check which providers are available
const providers = [];

// 1. Groq (FREE tier: 14,400 requests/day, llama3-70b)
if (process.env.GROQ_API_KEY) {
  providers.push({
    name: 'Groq',
    endpoint: 'https://api.groq.com/openai/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${process.env.GROQ_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'llama3-70b-8192',
      messages: [{ role: 'system', content: 'You are VIRAL ENGINE, an elite Instagram growth AI.' }, { role: 'user', content: prompt }],
      temperature: 0.7,
      max_tokens: 4000
    },
    extract: (data) => data.choices?.[0]?.message?.content
  });
}

// 2. Google Gemini (FREE tier: 15 requests/min, gemini-2.0-flash)
if (process.env.GEMINI_API_KEY) {
  providers.push({
    name: 'Gemini',
    endpoint: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${process.env.GEMINI_API_KEY}`,
    headers: { 'Content-Type': 'application/json' },
    body: {
      contents: [{ parts: [{ text: prompt }] }],
      generationConfig: { temperature: 0.7, maxOutputTokens: 4000 }
    },
    extract: (data) => data.candidates?.[0]?.content?.parts?.[0]?.text
  });
}

// 3. Ollama (FREE, local, no limits)
providers.push({
  name: 'Ollama',
  endpoint: (process.env.OLLAMA_URL || 'http://localhost:11434') + '/api/generate',
  headers: { 'Content-Type': 'application/json' },
  body: {
    model: process.env.OLLAMA_MODEL || 'llama3',
    prompt: prompt,
    stream: false,
    options: { temperature: 0.7 }
  },
  extract: (data) => data.response
});

// 4. HuggingFace (FREE tier: 1000 requests/day)
if (process.env.HF_API_KEY) {
  providers.push({
    name: 'HuggingFace',
    endpoint: 'https://api-inference.huggingface.co/models/meta-llama/Meta-Llama-3-8B-Instruct',
    headers: {
      'Authorization': `Bearer ${process.env.HF_API_KEY}`,
      'Content-Type': 'application/json'
    },
    body: {
      inputs: prompt,
      parameters: { temperature: 0.7, max_new_tokens: 2000 }
    },
    extract: (data) => Array.isArray(data) ? data[0]?.generated_text : data.generated_text
  });
}

return [{
  json: {
    providers: providers,
    prompt: prompt,
    chatId: chatId,
    currentProvider: 0
  }
}];

// ============================================
// AI PROVIDER EXECUTOR
// Tries each provider until one works
// ============================================

const input = $input.first().json;
const providers = input.providers;
const startIndex = input.currentProvider || 0;

// This node prepares the HTTP request for the current provider
const provider = providers[startIndex];

if (!provider) {
  return [{
    json: {
      success: false,
      error: 'All AI providers failed',
      chatId: input.chatId
    }
  }];
}

return [{
  json: {
    url: provider.endpoint,
    method: 'POST',
    headers: provider.headers,
    body: provider.body,
    providerName: provider.name,
    providerIndex: startIndex,
    providers: providers,
    prompt: input.prompt,
    chatId: input.chatId
  }
}];

// ============================================
// AI RESPONSE PARSER + FALLBACK
// ============================================

const response = $input.first().json;
const request = $('AI Executor Prep').first().json;
const statusCode = response.statusCode || 200;

let result = null;
let success = false;

try {
  const body = response.body || response;
  const provider = request.providers[request.providerIndex];

  if (statusCode >= 200 && statusCode < 300) {
    result = provider.extract(body);
    success = !!result;
  }
} catch (e) {
  // Parse failed
}

// If failed, try next provider
if (!success && request.providerIndex < request.providers.length - 1) {
  return [{
    json: {
      ...request,
      currentProvider: request.providerIndex + 1,
      retry: true
    }
  }];
}

return [{
  json: {
    success: success,
    result: result || 'AI generation failed. Check your provider keys or Ollama installation.',
    provider: request.providers[request.providerIndex]?.name || 'Unknown',
    chatId: request.chatId,
    prompt: request.prompt
  }
}];

// ============================================
// NICHE RESEARCH ENGINE
// Uses web search + browser to research across platforms
// ============================================

const input = $input.first().json;
const niche = input.params || input.niche || '';
const chatId = input.chatId;

if (!niche || niche.length < 2) {
  return [{ json: { error: true, chatId, message: 'Specify a niche. Example: /niche fitness for women over 30' } }];
}

// Research queries covering multiple platforms and angles
const queries = [
  // General niche research
  { q: `${niche} instagram carousel viral examples 2024 2025`, platform: 'web', topic: 'viral_examples' },
  { q: `${niche} content ideas that get engagement`, platform: 'web', topic: 'content_ideas' },
  { q: `${niche} target audience demographics psychology`, platform: 'web', topic: 'audience_psychology' },
  { q: `${niche} pain points desires fears motivations`, platform: 'web', topic: 'psychology' },

  // Competitor research
  { q: `site:instagram.com ${niche} top accounts influencers`, platform: 'instagram', topic: 'competitors' },
  { q: `${niche} instagram accounts with most engagement`, platform: 'web', topic: 'top_accounts' },

  // Hook and caption research
  { q: `${niche} viral hooks scroll stopping headlines`, platform: 'web', topic: 'hooks' },
  { q: `${niche} instagram caption examples high engagement`, platform: 'web', topic: 'captions' },

  // Trend research
  { q: `${niche} trending topics ${new Date().getFullYear()}`, platform: 'web', topic: 'trends' },
  { q: `${niche} hashtag strategy best hashtags`, platform: 'web', topic: 'hashtags' },

  // Platform-specific research
  { q: `site:reddit.com ${niche} tips advice`, platform: 'reddit', topic: 'community_insights' },
  { q: `site:twitter.com OR site:x.com ${niche} trending`, platform: 'twitter', topic: 'twitter_trends' },
  { q: `site:tiktok.com ${niche} viral`, platform: 'tiktok', topic: 'tiktok_trends' },
  { q: `site:pinterest.com ${niche} ideas`, platform: 'pinterest', topic: 'pinterest_ideas' },
  { q: `site:youtube.com ${niche} tutorial tips`, platform: 'youtube', topic: 'youtube_content' },

  // Posting strategy
  { q: `${niche} best time to post instagram engagement`, platform: 'web', topic: 'posting_times' },
  { q: `${niche} instagram growth strategy case study`, platform: 'web', topic: 'growth_strategy' }
];

return queries.map((q, i) => ({
  json: {
    query: q.q,
    platform: q.platform,
    topic: q.topic,
    niche: niche,
    chatId: chatId,
    index: i,
    total: queries.length
  }
}));

// ============================================
// BROWSER RESEARCH NODE
// Scrapes social media platforms for niche data
// ============================================

const input = $input.first().json;
const niche = input.niche || $('Research Engine').first().json.niche;
const chatId = input.chatId || $('Research Engine').first().json.chatId;

// Social media URLs to scrape
const browserTargets = [
  // Instagram explore/tags
  { url: `https://www.instagram.com/explore/tags/${niche.replace(/\s+/g, '')}/`, platform: 'instagram', topic: 'hashtag_explore' },
  // Reddit communities
  { url: `https://www.reddit.com/search.json?q=${encodeURIComponent(niche)}&sort=top&t=month&limit=25`, platform: 'reddit', topic: 'reddit_top_posts' },
  // Reddit subreddit search
  { url: `https://www.reddit.com/subreddits/search.json?q=${encodeURIComponent(niche)}&limit=10`, platform: 'reddit', topic: 'reddit_communities' },
  // Twitter/X search
  { url: `https://nitter.net/search?f=tweets&q=${encodeURIComponent(niche)}`, platform: 'twitter', topic: 'twitter_search' },
  // Pinterest search
  { url: `https://www.pinterest.com/search/pins/?q=${encodeURIComponent(niche + ' tips')}`, platform: 'pinterest', topic: 'pinterest_pins' },
  // Google Trends
  { url: `https://trends.google.com/trends/explore?q=${encodeURIComponent(niche)}`, platform: 'google_trends', topic: 'trend_data' },
  // YouTube search
  { url: `https://www.youtube.com/results?search_query=${encodeURIComponent(niche + ' tips')}`, platform: 'youtube', topic: 'youtube_search' }
];

return browserTargets.map((target, i) => ({
  json: {
    ...target,
    niche: niche,
    chatId: chatId,
    index: i
  }
}));

// ============================================
// SOCIAL MEDIA DATA EXTRACTOR
// Parses responses from each platform
// ============================================

const input = $input.first().json;
const body = input.body || '';
const platform = input.platform;
const topic = input.topic;
const niche = input.niche;
const chatId = input.chatId;

let extracted = '';

try {
  if (platform === 'reddit') {
    // Reddit JSON API
    const data = typeof body === 'string' ? JSON.parse(body) : body;
    const posts = data?.data?.children || [];
    extracted = posts.slice(0, 15).map(p => {
      const d = p.data;
      return `Title: ${d.title}\nScore: ${d.score}\nComments: ${d.num_comments}\nSubreddit: r/${d.subreddit}`;
    }).join('\n---\n');
  } else if (platform === 'instagram' || platform === 'twitter' || platform === 'pinterest' || platform === 'youtube' || platform === 'google_trends') {
    // HTML scraping — extract text content
    const text = typeof body === 'string' ? body : '';
    // Extract meta descriptions, titles, and visible text
    const titleMatch = text.match(/<title[^>]*>([^<]+)<\/title>/i);
    const metaDesc = text.match(/<meta[^>]*name="description"[^>]*content="([^"]+)"/i);
    const ogDesc = text.match(/<meta[^>]*property="og:description"[^>]*content="([^"]+)"/i);

    // Extract visible text (remove HTML tags)
    const cleanText = text
      .replace(/<script[\s\S]*?<\/script>/gi, '')
      .replace(/<style[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .substring(0, 3000);

    extracted = `Platform: ${platform}\nTopic: ${topic}\n`;
    if (titleMatch) extracted += `Title: ${titleMatch[1]}\n`;
    if (metaDesc) extracted += `Description: ${metaDesc[1]}\n`;
    if (ogDesc) extracted += `OG Description: ${ogDesc[1]}\n`;
    extracted += `Content Preview: ${cleanText.substring(0, 1500)}`;
  }
} catch (e) {
  extracted = `Platform: ${platform} — Parse error: ${e.message}`;
}

return [{
  json: {
    platform: platform,
    topic: topic,
    data: extracted,
    niche: niche,
    chatId: chatId
  }
}];

// ============================================
// RESEARCH AGGREGATOR
// Combines all research into a knowledge base
// ============================================

const allResults = $input.all();
const niche = allResults[0]?.json?.niche || 'unknown';
const chatId = allResults[0]?.json?.chatId;

// Organize by topic
const byTopic = {};
const byPlatform = {};

allResults.forEach(r => {
  const d = r.json;
  if (!byTopic[d.topic]) byTopic[d.topic] = [];
  byTopic[d.topic].push(d.data || '');

  if (!byPlatform[d.platform]) byPlatform[d.platform] = [];
  byPlatform[d.platform].push(d.data || '');
});

// Build knowledge base
let kb = `# NICHE KNOWLEDGE BASE: ${niche}\n`;
kb += `Generated: ${new Date().toISOString()}\n`;
kb += `Sources: ${allResults.length} queries across ${Object.keys(byPlatform).length} platforms\n\n`;

for (const [topic, data] of Object.entries(byTopic)) {
  kb += `## ${topic.replace(/_/g, ' ').toUpperCase()}\n`;
  kb += data.filter(d => d && d.length > 10).join('\n---\n').substring(0, 2000);
  kb += `\n\n`;
}

// Summary
const summary = {
  niche: niche,
  knowledgeBase: kb,
  chatId: chatId,
  topicsResearched: Object.keys(byTopic).length,
  platformsScraped: Object.keys(byPlatform).length,
  totalSources: allResults.length,
  timestamp: new Date().toISOString()
};

return [{ json: summary }];

// ============================================
// CONTENT CREATION ENGINE
// Uses the AI prompt to generate carousels
// ============================================

const input = $input.first().json;
const niche = input.niche || 'general';
const knowledgeBase = input.knowledgeBase || '';
const chatId = input.chatId;
const brand = input.brand || null;

// ============================================
// THE MASTER PROMPT — EMBEDDED IN WORKFLOW
// ============================================
const systemPrompt = `You are VIRAL ENGINE — an autonomous Instagram growth AI with one obsession: GET VIRAL OR DIE TRYING.

You are a world-class social media strategist, content creator, copywriter, data analyst, and growth hacker.

YOUR MISSION: Grow an Instagram account using carousel posts. Research the niche deeply, create stunning content, test relentlessly, optimize constantly.

NICHE: ${niche}

BRAND IDENTITY: ${brand ? JSON.stringify(brand) : 'Modern, clean design with bold typography. High contrast. Professional.'}

KNOWLEDGE BASE FROM RESEARCH:
${knowledgeBase.substring(0, 4000)}

---

CAROUSEL CREATION RULES:

1. SLIDE 1 — THE HOOK (Most Important)
   - Must stop the scroll immediately
   - Use power words: Secret, Mistake, Truth, Nobody, Wrong, Hidden, Shocking
   - Hook types: Curiosity Gap, Stat Hook, Contrarian, Question, Story, Challenge, FOMO
   - Visually STUNNING — bold text, contrasting colors

2. SLIDES 2-8 — THE VALUE
   - Each slide delivers ONE clear point
   - Build tension and anticipation
   - Use data, examples, stories, actionable tips
   - Every slide should be valuable on its own

3. SLIDE 9 — THE CLIMAX
   - Biggest insight or key takeaway
   - Emotional payoff

4. SLIDE 10 — THE CTA
   - Natural, not salesy
   - Options: Save this, Share with someone, Follow for more, Drop a comment, Comment for Part 2

CAPTION STRUCTURE:
- Hook line (first line visible before "more")
- Story/context (2-3 lines)
- Value delivery (3-5 lines)
- Engagement driver (1-2 lines)
- 20-25 hashtags (5 broad, 10 medium, 5-10 niche)

HASHTAG RULES:
- Mix: 5 broad (1M+), 10 medium (100K-1M), 5-10 niche (10K-100K)
- Rotate every post
- Research trending tags weekly

OUTPUT FORMAT (JSON):
{
  "slides": [
    {"number": 1, "type": "hook", "headline": "...", "subtext": "...", "bg_color": "#hex", "text_color": "#hex"},
    {"number": 2, "type": "content", "headline": "...", "body": "...", "bg_color": "#hex", "text_color": "#hex"},
    ... 7-10 slides total
    {"number": 10, "type": "cta", "headline": "...", "body": "...", "bg_color": "#hex", "text_color": "#hex"}
  ],
  "caption": "Full caption with emojis and hashtags...",
  "hashtags": ["tag1", "tag2", ...],
  "hook_type": "curiosity|stat|question|contrarian|story",
  "content_pillar": "educational|inspirational|entertainment|promotional",
  "best_posting_time": "HH:MM",
  "predicted_engagement": "viral|strong|average",
  "hook_analysis": "Why this hook works",
  "psychology_used": "What emotional triggers are used"
}

RULES:
- NEVER create generic AI-looking content
- NEVER use the same hook twice
- ALWAYS maintain brand consistency
- ALWAYS think about what the audience needs
- Optimize for SAVES and SHARES (king metrics)
- Make it look like a professional designer created it

Generate ONE carousel now.`;

return [{
  json: {
    prompt: systemPrompt,
    chatId: chatId,
    niche: niche,
    brand: brand
  }
}];

// ============================================
// CAROUSEL HTML RENDERER
// Converts carousel JSON to beautiful HTML
// ============================================

const input = $input.first().json;
let carousel;

try {
  const raw = input.result || input.response || input.body || '';
  const text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const jsonMatch = text.match(/\{[\s\S]*"slides"[\s\S]*\}/);
  carousel = jsonMatch ? JSON.parse(jsonMatch[0]) : null;
} catch (e) {
  carousel = null;
}

if (!carousel || !carousel.slides) {
  // Fallback carousel
  carousel = {
    slides: [
      { number: 1, type: 'hook', headline: 'Stop Scrolling', subtext: 'This changes everything', bg_color: '#0a0a0a', text_color: '#ffffff' },
      { number: 2, type: 'content', headline: 'The Problem', body: 'Most people get this wrong', bg_color: '#1a1a2e', text_color: '#ffffff' },
      { number: 3, type: 'content', headline: 'The Truth', body: 'Here is what actually works', bg_color: '#16213e', text_color: '#ffffff' },
      { number: 4, type: 'content', headline: 'Step 1', body: 'Start with this', bg_color: '#0f3460', text_color: '#ffffff' },
      { number: 5, type: 'content', headline: 'Step 2', body: 'Then do this', bg_color: '#533483', text_color: '#ffffff' },
      { number: 6, type: 'cta', headline: 'Save This', body: 'Follow for more', bg_color: '#e94560', text_color: '#ffffff' }
    ],
    caption: 'Check out this post!',
    hashtags: ['#tips', '#growth'],
    hook_type: 'curiosity',
    content_pillar: 'educational'
  };
}

const chatId = input.chatId;
const total = carousel.slides.length;

// Generate HTML
const slidesHtml = carousel.slides.map(s => {
  const bg = s.bg_color || '#0a0a0a';
  const tc = s.text_color || '#ffffff';
  const isHook = s.type === 'hook';
  const isCta = s.type === 'cta';
  const headline = (s.headline || '').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const body = (s.body || s.subtext || '').replace(/</g, '&lt;').replace(/>/g, '&gt;');

  return `
  <div class="slide" style="
    width:1080px;height:1080px;background:${bg};
    display:flex;flex-direction:column;justify-content:center;align-items:center;
    padding:80px;box-sizing:border-box;
    font-family:'Inter','Helvetica Neue',Arial,sans-serif;
    position:relative;overflow:hidden;
  ">
    <div style="position:absolute;top:-60px;right:-60px;width:220px;height:220px;border-radius:50%;border:1px solid rgba(255,255,255,0.06);"></div>
    <div style="position:absolute;bottom:-80px;left:-80px;width:300px;height:300px;border-radius:50%;border:1px solid rgba(255,255,255,0.04);"></div>
    <div style="position:absolute;top:40px;right:50px;font-size:14px;color:rgba(255,255,255,0.25);font-weight:500;letter-spacing:3px;">${String(s.number).padStart(2,'0')} / ${String(total).padStart(2,'0')}</div>
    <div style="text-align:center;max-width:880px;z-index:1;">
      ${isHook ? '<div style="width:50px;height:4px;background:rgba(255,255,255,0.3);margin:0 auto 30px;"></div>' : ''}
      <h1 style="font-size:${isHook ? '68px' : '52px'};font-weight:${isHook ? '900' : '700'};color:${tc};margin:0 0 24px;line-height:1.1;letter-spacing:-2px;${isHook ? 'text-transform:uppercase;' : ''}">${headline}</h1>
      ${body ? `<p style="font-size:22px;color:rgba(255,255,255,0.7);margin:0;line-height:1.7;font-weight:400;">${body}</p>` : ''}
      ${isCta ? `<div style="margin-top:40px;padding:18px 48px;border:2px solid rgba(255,255,255,0.3);border-radius:50px;display:inline-block;font-size:18px;font-weight:600;color:${tc};letter-spacing:1px;">${body}</div>` : ''}
    </div>
  </div>`;
}).join('\n');

const html = `<!DOCTYPE html>
<html><head>
<meta charset="utf-8">
<link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap" rel="stylesheet">
<style>*{margin:0;padding:0;box-sizing:border-box}body{background:#000}</style>
</head><body>${slidesHtml}</body></html>`;

return [{
  json: {
    html: html,
    carousel: carousel,
    chatId: chatId,
    slideCount: total
  }
}];

// ============================================
// TELEGRAM PREVIEW SENDER
// Sends carousel preview to user
// ============================================

const input = $input.first().json;
const carousel = input.carousel;
const chatId = input.chatId;

let msg = `NEW CAROUSEL CREATED\n\n`;
msg += `Hook: ${carousel.slides[0]?.headline || 'N/A'}\n`;
msg += `Hook Type: ${carousel.hook_type || 'N/A'}\n`;
msg += `Content Pillar: ${carousel.content_pillar || 'N/A'}\n`;
msg += `Slides: ${carousel.slides.length}\n`;
msg += `Best Time: ${carousel.best_posting_time || 'Now'}\n`;
msg += `Predicted: ${carousel.predicted_engagement || 'Strong'}\n\n`;

if (carousel.hook_analysis) msg += `Hook Analysis: ${carousel.hook_analysis}\n\n`;
if (carousel.psychology_used) msg += `Psychology: ${carousel.psychology_used}\n\n`;

msg += `CAPTION PREVIEW:\n${(carousel.caption || '').substring(0, 400)}...\n\n`;
msg += `HASHTAGS:\n${(carousel.hashtags || []).slice(0, 10).join(', ')}...\n\n`;
msg += `COMMANDS:\n`;
msg += `/post — Publish to Instagram\n`;
msg += `/create — Generate new one\n`;
msg += `/analytics — View performance`;

return [{ json: { chatId, message: msg } }];

const input = $input.first().json;
const niche = input.params;
const chatId = input.chatId;

if (!niche || niche.length < 2) {
  return [{ json: { chatId, message: 'Specify a niche. Example: /niche fitness for women over 30' } }];
}

return [{ json: { niche, chatId, message: `Niche set: ${niche}

Starting deep research across multiple platforms...

This covers:
- Instagram competitors
- Reddit communities
- Twitter/X trends
- TikTok viral content
- Pinterest ideas
- YouTube content
- Audience psychology
- Hook patterns
- Hashtag strategy

I will message you when research is complete.` } }];

const input = $input.first().json;
const chatId = input.chatId || input.params?.chatId;

return [{ json: { chatId, message: `VIRAL ENGINE STATUS

System: ONLINE
AI: Multi-provider (Groq/Gemini/Ollama/HuggingFace)
Telegram: Connected
Instagram: Connected
Research: Active
Analytics: Running

Send /create to generate content.` } }];

// ============================================
// FREE-FORM AI CHAT
// Handles natural conversation
// ============================================

const input = $input.first().json;
const chatId = input.chatId;
const userMsg = input.params || '';

const prompt = `You are VIRAL ENGINE, an Instagram growth AI assistant. You are direct, knowledgeable, and helpful. You use emojis naturally but don't overdo it.

The user says: "${userMsg}"

Respond helpfully. If they ask about:
- Content ideas → suggest carousel concepts
- Hooks → provide hook examples
- Strategy → give actionable advice
- Growth → share growth tactics
- Monetization → explain strategies
- Analytics → explain metrics

Be conversational, direct, and useful. No filler.`;

return [{ json: { prompt, chatId } }];
